import puppeteer from 'puppeteer-core';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const browser = await puppeteer.launch({
  executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
  headless: 'new',
  args: ['--window-size=1440,900', '--hide-scrollbars'],
  defaultViewport: { width: 1440, height: 900 },
});
const page = await browser.newPage();
await page.goto('https://bug-bash.github.com/', { waitUntil: 'networkidle2', timeout: 60000 });

// let the game boot and any intro animation play
await sleep(6000);
await page.screenshot({ path: '/tmp/bb-1-landing.png' });

// log what's in the game container for context
const info = await page.evaluate(() => {
  const c = document.querySelector('#game-container');
  return c ? c.innerHTML.slice(0, 2000) : 'no #game-container';
});
console.log('CONTAINER:', info);

// click center of the canvas / press keys that arcade games commonly use to advance
const canvas = await page.$('canvas');
if (canvas) {
  const box = await canvas.boundingBox();
  await page.mouse.click(box.x + box.width / 2, box.y + box.height / 2);
}
await sleep(2000);
await page.screenshot({ path: '/tmp/bb-2-after-click.png' });

await page.keyboard.press('Enter');
await sleep(2000);
await page.screenshot({ path: '/tmp/bb-3-after-enter.png' });

await page.keyboard.press('Space');
await sleep(3000);
await page.screenshot({ path: '/tmp/bb-4-after-space.png' });

await browser.close();
console.log('done');

