import puppeteer from 'puppeteer-core';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const browser = await puppeteer.launch({
  executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
  headless: 'new',
  args: ['--window-size=1440,900', '--hide-scrollbars'],
  defaultViewport: { width: 1440, height: 900, deviceScaleFactor: 2 },
});
const page = await browser.newPage();
await page.goto('https://bug-bash.github.com/', { waitUntil: 'networkidle2', timeout: 60000 });
await sleep(6000);

const canvas = await page.$('canvas');
const box = await canvas.boundingBox();
const shot = (name) => page.screenshot({ path: `/tmp/bb-${name}.png`, clip: box });

await shot('t1-title');

// focus the canvas, then click "Start Game" (menu cursor sits on it)
await page.mouse.click(box.x + box.width / 2, box.y + box.height * 0.6);
await sleep(300);
await page.mouse.click(box.x + box.width / 2, box.y + box.height * 0.6);
await sleep(1500);
await shot('t2-after-start-click');

for (let i = 0; i < 6; i++) {
  await page.keyboard.press('Enter');
  await sleep(1800);
  await shot(`t3-step${i}`);
}

// let gameplay run a bit, press some arrows
for (const k of ['ArrowRight', 'ArrowRight', 'ArrowUp', 'ArrowLeft']) {
  await page.keyboard.down(k);
  await sleep(400);
  await page.keyboard.up(k);
}
await sleep(1500);
await shot('t4-gameplay');
await sleep(4000);
await shot('t5-gameplay-later');

await browser.close();
console.log('done');

