import puppeteer from 'puppeteer-core';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const browser = await puppeteer.launch({
  executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
  headless: 'new',
  args: ['--window-size=1440,900', '--hide-scrollbars'],
  defaultViewport: { width: 1440, height: 900, deviceScaleFactor: 2 },
});
const page = await browser.newPage();
await page.goto('https://bug-bash.github.com/', { waitUntil: 'networkidle2', timeout: 60000 });
await sleep(6000);

const canvas = await page.$('canvas');
const box = await canvas.boundingBox();
const shot = (name) => page.screenshot({ path: `/tmp/bbs-${name}.png`, clip: box });

// start game
await page.mouse.click(box.x + box.width / 2, box.y + box.height * 0.6);
await sleep(300);
await page.mouse.click(box.x + box.width / 2, box.y + box.height * 0.6);
await sleep(1500);

// advance the cutscene / instructions with Space, capturing every screen
for (let i = 0; i < 12; i++) {
  await page.keyboard.press('Space');
  await sleep(2200);
  await shot(`s${String(i).padStart(2, '0')}`);
}

// then try to play a little
for (const k of ['ArrowRight', 'ArrowRight', 'ArrowUp', 'Space', 'ArrowLeft']) {
  await page.keyboard.down(k);
  await sleep(350);
  await page.keyboard.up(k);
  await sleep(200);
}
await sleep(1500);
await shot('s90-play');
await sleep(5000);
await shot('s91-play-later');

await browser.close();
console.log('done');

