11	
12	* { margin: 0; padding: 0; box-sizing: border-box; }
13	
14	html, body {
15	  width: 100%;
16	  height: 100%;
17	  overflow: hidden;
18	  background: #02040a;
19	  color: var(--ink);
20	  font-family: "SF Mono", "JetBrains Mono", ui-monospace, Menlo, monospace;
21	  cursor: default;
22	}
23	
24	#scene {
25	  position: fixed;
26	  inset: 0;
27	  display: block;
28	  width: 100%;
29	  height: 100%;
30	}
31	
32	#ui {
33	  position: fixed;
34	  inset: 0;
35	  pointer-events: none;
36	  z-index: 10;
37	}
38	
39	#hud {
40	  position: absolute;
41	  top: 28px;
42	  left: 32px;
43	}
44	
45	.hud-title {
46	  font-size: 26px;
47	  letter-spacing: 0.42em;
48	  font-weight: 600;
49	  text-shadow: 0 0 18px rgba(111, 227, 255, 0.55);
50	}
51	
52	#hint {
53	  position: absolute;
54	  bottom: 26px;
55	  left: 50%;
56	  transform: translateX(-50%);
57	  font-size: 12px;
58	  letter-spacing: 0.12em;
59	  opacity: 0.55;
60	  white-space: nowrap;
61	}
62	
63	/* Background music controls */
64	#audio-panel {
65	  position: absolute;
66	  top: 28px;
67	  right: 32px;
68	  display: flex;
69	  align-items: center;
70	  gap: 8px;
71	  padding: 8px 10px;
72	  background: rgba(8, 14, 26, 0.58);
73	  border: 1px solid rgba(255, 244, 232, 0.18);
74	  border-radius: 6px;
75	  box-shadow: 0 12px 36px rgba(2, 4, 10, 0.34);
76	  backdrop-filter: blur(10px);
77	  pointer-events: auto;
78	}
79	
80	.audio-mark {
81	  display: inline-flex;
82	  align-items: center;
83	  justify-content: center;
84	  width: 30px;
85	  height: 30px;
86	  color: rgba(255, 210, 122, 0.84);
87	}
88	
89	.icon-button {
90	  display: inline-flex;
91	  align-items: center;
92	  justify-content: center;
93	  width: 30px;
94	  height: 30px;
95	  border: 1px solid rgba(255, 244, 232, 0.22);
96	  border-radius: 50%;
97	  background: rgba(255, 244, 232, 0.08);
98	  color: var(--ink);
99	  cursor: pointer;
100	  transition: background 0.18s ease, border-color 0.18s ease, transform 0.18s ease;
101	}
102	
103	.icon-button:hover,
104	.icon-button:focus-visible {
105	  background: rgba(255, 184, 107, 0.16);
106	  border-color: rgba(255, 210, 122, 0.55);
107	  outline: none;
108	  transform: translateY(-1px);
109	}
110	
111	#audio-panel.is-awaiting-start #audio-toggle {
112	  border-color: rgba(255, 210, 122, 0.7);
113	  animation: audio-start-pulse 1.6s ease-in-out infinite;
114	}
115	
116	.icon {
117	  width: 15px;
118	  height: 15px;
119	  display: block;
120	  fill: currentColor;
121	}
122	
123	.icon-pause,
124	#audio-toggle.is-playing .icon-play {
125	  display: none;
126	}
127	
128	#audio-toggle.is-playing .icon-pause {
129	  display: block;
130	}
131	
132	.icon-speaker .mute-mark {
133	  fill: none;
134	  stroke: currentColor;
135	  stroke-width: 1.8;
136	  stroke-linecap: round;
137	  opacity: 0;
138	}
139	
140	#audio-mute.is-muted .mute-mark {
141	  opacity: 1;
142	}
143	
144	#audio-volume {
145	  width: 92px;
146	  accent-color: var(--accent-warm);
147	  cursor: pointer;
148	}
149	
150	#audio-volume:focus-visible {
151	  outline: 1px solid rgba(255, 210, 122, 0.75);
152	  outline-offset: 3px;
153	}
154	
155	@keyframes audio-start-pulse {
156	  0%, 100% {
157	    box-shadow: 0 0 0 rgba(255, 184, 107, 0);
158	  }
159	  50% {
160	    box-shadow: 0 0 14px rgba(255, 184, 107, 0.42);
161	  }
162	}
