199	/* Ship memory gauge — the level goal; only checkpoints fill it. A thick
200	   VERTICAL bar under the clock that fills bottom-up and shifts colour as the
201	   ship's memory is restored (warning amber → cyan → restored aqua-green). */
202	#ship-meter {
203	  position: absolute;
204	  top: 136px;
205	  left: 32px;
206	  display: flex;
207	  flex-direction: column;
208	  align-items: center;
209	  gap: 10px;
210	  padding: 12px 14px;
211	  background: rgba(6, 11, 22, 0.7);
212	  border: 1px solid rgba(111, 227, 255, 0.32);
213	  border-radius: 12px;
214	  backdrop-filter: blur(8px);
215	}
216	
217	.meter-label {
218	  font-size: 9.5px;
219	  letter-spacing: 0.18em;
220	  font-weight: 700;
221	  color: var(--accent);
222	  opacity: 0.95;
223	  white-space: nowrap;
224	}
225	
226	.meter-track {
227	  position: relative;
228	  width: 22px;
229	  height: 150px;
230	  border-radius: 11px;
231	  background: rgba(111, 227, 255, 0.12);
232	  border: 1px solid rgba(111, 227, 255, 0.18);
233	  overflow: hidden;
234	}
235	
236	#ship-meter-fill {
237	  position: absolute;
238	  left: 0;
239	  right: 0;
240	  bottom: 0;
241	  height: 0%;
242	  border-radius: 11px;
243	  background: rgba(111, 227, 255, 0.4);
244	  transition: height 0.6s cubic-bezier(0.22, 1, 0.36, 1),
245	              background 0.5s ease, box-shadow 0.5s ease;
246	}
247	/* colour climbs with the fill */
248	#ship-meter.lvl-low #ship-meter-fill {
249	  background: linear-gradient(180deg, #ffc46b, #ff8a3c);
250	  box-shadow: 0 0 14px rgba(255, 150, 80, 0.7);
251	}
252	#ship-meter.lvl-mid #ship-meter-fill {
253	  background: linear-gradient(180deg, #9af0ff, #3aa6c8);
254	  box-shadow: 0 0 16px rgba(111, 227, 255, 0.8);
255	}
256	#ship-meter.lvl-high #ship-meter-fill {
257	  background: linear-gradient(180deg, #bfffe0, #5cffb0);
258	  box-shadow: 0 0 22px rgba(92, 255, 176, 0.95);
259	}
260	
261	#ship-meter.is-full { border-color: rgba(92, 255, 176, 0.6); }
262	#ship-meter.is-full #ship-meter-fill { animation: meter-glow 1.8s ease-in-out infinite; }
263	
264	#ship-meter-pct {
265	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
266	  font-size: 15px;
267	  font-weight: 700;
268	  letter-spacing: 0.02em;
269	  text-align: center;
270	  color: var(--ink);
271	  opacity: 0.95;
272	  font-variant-numeric: tabular-nums;
273	}
274	
275	@keyframes meter-glow {
276	  0%, 100% { filter: brightness(1); }
277	  50% { filter: brightness(1.4); }
278	}
