280	/* Level countdown clock (top-left, under the PLANETFALL title).
281	   Shared by Level 1 (#countdown), the Drone Bay (#db-countdown), and the
282	   shelved Archive level (#l2-countdown). */
283	#countdown,
284	#l2-countdown,
285	#db-countdown,
286	#lc-countdown {
287	  position: absolute;
288	  top: 78px;
289	  left: 32px;
290	  display: flex;
291	  align-items: center;
292	  gap: 11px;
293	  padding: 8px 16px;
294	  background: rgba(6, 11, 22, 0.78);
295	  border: 1px solid rgba(111, 227, 255, 0.4);
296	  border-radius: 9px;
297	  backdrop-filter: blur(8px);
298	  transition: border-color 0.3s ease, background 0.3s ease;
299	}
300	
301	.cd-label {
302	  font-size: 10.5px;
303	  letter-spacing: 0.24em;
304	  font-weight: 700;
305	  color: var(--accent);
306	  opacity: 0.95;
307	}
308	
309	#countdown-time,
310	#l2-countdown-time,
311	#db-countdown-time,
312	#lc-countdown-time {
313	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
314	  font-size: 27px;
315	  font-weight: 700;
316	  letter-spacing: 0.02em;
317	  color: var(--ink);
318	  min-width: 66px;
319	  text-align: right;
320	  font-variant-numeric: tabular-nums;
321	}
322	
323	/* Urgent state — the clock is running low */
324	#countdown.is-low,
325	#l2-countdown.is-low,
326	#db-countdown.is-low,
327	#lc-countdown.is-low {
328	  border-color: rgba(255, 90, 90, 0.7);
329	  background: rgba(40, 10, 12, 0.6);
330	  animation: cd-pulse 1s ease-in-out infinite;
331	}
332	#countdown.is-low .cd-label,
333	#l2-countdown.is-low .cd-label,
334	#db-countdown.is-low .cd-label,
335	#lc-countdown.is-low .cd-label { color: #ff7a6b; }
336	#countdown.is-low #countdown-time,
337	#l2-countdown.is-low #l2-countdown-time,
338	#db-countdown.is-low #db-countdown-time,
339	#lc-countdown.is-low #lc-countdown-time { color: #ff8a78; }
340	
341	@keyframes cd-pulse {
342	  0%, 100% { box-shadow: 0 0 0 rgba(255, 90, 90, 0); }
343	  50% { box-shadow: 0 0 18px rgba(255, 90, 90, 0.55); }
344	}
345	
346	/* Critical state — under a few seconds, the clock goes frantic */
347	#countdown.is-critical,
348	#l2-countdown.is-critical,
349	#db-countdown.is-critical,
350	#lc-countdown.is-critical {
351	  border-color: rgba(255, 60, 60, 0.95);
352	  background: rgba(60, 8, 10, 0.72);
353	  animation: cd-panic 0.5s steps(2, end) infinite;
354	}
355	#countdown.is-critical .cd-label,
356	#l2-countdown.is-critical .cd-label,
357	#db-countdown.is-critical .cd-label,
358	#lc-countdown.is-critical .cd-label { color: #ff4d4d; }
359	#countdown.is-critical #countdown-time,
360	#l2-countdown.is-critical #l2-countdown-time,
361	#db-countdown.is-critical #db-countdown-time,
362	#lc-countdown.is-critical #lc-countdown-time {
363	  color: #ff5a4d;
364	  text-shadow: 0 0 12px rgba(255, 70, 60, 0.9);
365	}
366	
367	@keyframes cd-panic {
368	  0% { box-shadow: 0 0 22px rgba(255, 50, 50, 0.8); transform: translateX(-1px); }
369	  100% { box-shadow: 0 0 8px rgba(255, 50, 50, 0.4); transform: translateX(1px); }
370	}
