1304	    width: min(240px, calc(100vw - 32px));
1305	    padding: 9px 11px;
1306	  }
1307	
1308	  #dev-level-badge {
1309	    top: 14px;
1310	    left: 16px;
1311	    padding: 7px 10px;
1312	  }
1313	  #dev-level-badge strong {
1314	    font-size: 14px;
1315	  }
1316	
1317	  #tutorial {
1318	    top: 56px;
1319	    font-size: 11.5px;
1320	    padding: 8px 12px;
1321	  }
1322	
1323	  #l2-request {
1324	    top: 58px;
1325	    left: 16px;
1326	    width: min(260px, calc(100vw - 32px));
1327	    padding: 9px 11px;
1328	  }
1329	
1330	  #action-bar { bottom: 120px; }
1331	
1332	  #terminal {
1333	    bottom: 56px;
1334	    padding: 11px 12px;
1335	  }
1336	  #term-line { font-size: 13.5px; }
1337	}
1338	
1339	/* Loader */
1340	#loader {
1341	  position: fixed;
1342	  inset: 0;
1343	  display: flex;
1344	  flex-direction: column;
1345	  align-items: center;
1346	  justify-content: center;
1347	  gap: 22px;
1348	  background: #02040a;
1349	  z-index: 50;
1350	  transition: opacity 0.8s ease;
1351	}
1352	
1353	#loader.done {
1354	  opacity: 0;
1355	  pointer-events: none;
1356	}
1357	
1358	.loader-ring {
1359	  width: 46px;
1360	  height: 46px;
1361	  border: 2px solid rgba(111, 227, 255, 0.2);
1362	  border-top-color: var(--accent);
1363	  border-radius: 50%;
1364	  animation: spin 0.9s linear infinite;
1365	}
1366	
1367	.loader-text {
1368	  font-size: 12px;
1369	  letter-spacing: 0.35em;
1370	  opacity: 0.7;
1371	}
1372	
1373	@keyframes spin { to { transform: rotate(360deg); } }
1374	
1375	.hidden { display: none; }
1376	
1377	/* ---------- Level 3 HUD ("Launch Clearance") ---------- */
1378	
1379	/* The briefing quotes the ship's AI — set the line apart. */
1380	.bf-quote {
1381	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
1382	  font-size: 12.5px;
1383	  color: var(--accent);
1384	  border-left: 2px solid rgba(111, 227, 255, 0.45);
1385	  padding-left: 12px;
1386	  margin-top: 10px;
1387	}
1388	
1389	/* The launch code — one segment per confirmed answer */
1390	#lc-code {
1391	  position: absolute;
1392	  top: 136px;
1393	  left: 32px;
1394	  padding: 12px 14px;
1395	  background: rgba(6, 11, 22, 0.78);
1396	  border: 1px solid rgba(255, 210, 122, 0.4);
1397	  border-radius: 9px;
1398	  backdrop-filter: blur(8px);
1399	}
1400	.lc-code-head {
1401	  font-size: 10px;
1402	  letter-spacing: 0.22em;
1403	  font-weight: 700;
1404	  color: var(--accent-warm);
1405	  margin-bottom: 9px;
1406	}
1407	#lc-code-segs {
1408	  display: flex;
1409	  gap: 6px;
1410	}
1411	.lc-seg {
1412	  display: inline-grid;
1413	  place-items: center;
1414	  min-width: 44px;
1415	  height: 26px;
1416	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
1417	  font-size: 12px;
1418	  letter-spacing: 0.08em;
1419	  color: var(--ink);
1420	  opacity: 0.4;
1421	  border: 1px dashed rgba(232, 244, 255, 0.35);
1422	  border-radius: 5px;
1423	}
1424	.lc-seg.is-locked {
1425	  opacity: 1;
1426	  color: #1a1206;
1427	  font-weight: 700;
1428	  border: none;
1429	  background: linear-gradient(90deg, #ffd27a, #ffe7b0);
1430	  box-shadow: 0 0 14px rgba(255, 210, 122, 0.5);
1431	}
1432	
1433	/* The pre-flight console — the whole level happens here */
1434	#lc-console {
1435	  position: absolute;
1436	  pointer-events: auto;
1437	  bottom: 70px;
1438	  left: 50%;
1439	  transform: translateX(-50%);
1440	  width: min(620px, calc(100vw - 40px));
1441	  padding: 15px 18px;
1442	  background: rgba(4, 10, 18, 0.88);
1443	  border: 1px solid rgba(111, 227, 255, 0.42);
1444	  border-radius: 8px;
1445	  box-shadow: 0 14px 40px rgba(2, 4, 10, 0.55), 0 0 24px rgba(111, 227, 255, 0.12);
1446	  backdrop-filter: blur(6px);
1447	  text-align: left;
1448	}
1449	#lc-console.hidden { display: none; }
1450	
1451	#lc-speaker {
1452	  font-size: 10px;
1453	  letter-spacing: 0.22em;
1454	  font-weight: 700;
1455	  color: var(--accent);
1456	  margin-bottom: 7px;
1457	}
1458	#lc-question {
1459	  font-size: 14.5px;
1460	  line-height: 1.5;
1461	  color: var(--ink);
1462	  margin-bottom: 12px;
1463	}
1464	
1465	/* The tool menu — pick a way to look it up */
1466	#lc-menu:not(.hidden) {
1467	  display: flex;
1468	  flex-direction: column;
1469	  gap: 6px;
1470	}
1471	.lc-opt {
1472	  display: flex;
1473	  align-items: center;
1474	  gap: 10px;
1475	  padding: 7px 10px;
1476	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
1477	  font-size: 13px;
1478	  text-align: left;
1479	  color: var(--ink);
1480	  cursor: pointer;
1481	  background: rgba(111, 227, 255, 0.07);
1482	  border: 1px solid rgba(111, 227, 255, 0.28);
1483	  border-radius: 7px;
1484	  transition: background 0.15s ease, border-color 0.15s ease, transform 0.1s ease;
1485	}
1486	.lc-opt:hover:not(:disabled):not(.is-dead) {
1487	  background: rgba(111, 227, 255, 0.16);
1488	  border-color: rgba(111, 227, 255, 0.55);
1489	  transform: translateY(-1px);
1490	}
1491	.lc-opt kbd {
1492	  display: inline-grid;
1493	  place-items: center;
1494	  min-width: 22px;
1495	  height: 22px;
1496	  font-family: inherit;
1497	  font-size: 12px;
1498	  font-weight: 700;
1499	  color: #04121a;
1500	  background: linear-gradient(90deg, #6fe3ff, #9af0ff);
1501	  border-radius: 5px;
1502	  flex: none;
1503	}
1504	.lc-opt.is-skill { border-color: rgba(255, 210, 122, 0.4); }
1505	.lc-opt.is-skill kbd { background: linear-gradient(90deg, #ffd27a, #ffe7b0); }
1506	.lc-opt.is-dead {
1507	  opacity: 0.38;
1508	  cursor: default;
1509	  text-decoration: line-through;
1510	}
1511	.lc-opt.is-used {
1512	  border-color: rgba(92, 255, 176, 0.5);
1513	  background: rgba(92, 255, 176, 0.08);
1514	}
1515	.lc-opt:disabled { cursor: default; }
1516	
1517	/* What the tool printed */
1518	#lc-output:not(.hidden) {
1519	  display: flex;
1520	  flex-direction: column;
1521	  gap: 5px;
1522	  margin-top: 12px;
1523	  padding-top: 10px;
1524	  border-top: 1px solid rgba(111, 227, 255, 0.16);
1525	  max-height: 178px;
1526	  overflow-y: auto;
1527	}
1528	.lc-row {
1529	  display: flex;
1530	  gap: 12px;
1531	  font-size: 12.5px;
1532	  line-height: 1.35;
1533	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
1534	}
1535	.lc-row .lc-k { color: var(--ink); opacity: 0.55; min-width: 96px; flex: none; }
1536	.lc-row .lc-v { color: var(--ink); opacity: 0.85; }
1537	.lc-echo { margin-bottom: 3px; }
1538	.lc-prompt { color: var(--accent); opacity: 0.9; flex: none; }
1539	.lc-cmd { color: var(--ink); }
1540	
1541	/* Confirm chips — the answer is on screen; click it */
1542	#lc-answers:not(.hidden) {
1543	  display: flex;
1544	  flex-wrap: wrap;
1545	  align-items: center;
1546	  gap: 8px;
1547	  margin-top: 12px;
1548	  padding-top: 10px;
1549	  border-top: 1px solid rgba(92, 255, 176, 0.2);
1550	}
1551	.lc-answers-head {
1552	  width: 100%;
1553	  font-size: 10px;
1554	  letter-spacing: 0.22em;
1555	  font-weight: 700;
1556	  color: #7cffb0;
1557	}
1558	.lc-chip {
1559	  display: flex;
1560	  align-items: center;
1561	  gap: 8px;
1562	  padding: 7px 12px;
1563	  font-family: inherit;
1564	  font-size: 12.5px;
1565	  font-weight: 600;
1566	  letter-spacing: 0.04em;
1567	  color: var(--ink);
1568	  cursor: pointer;
1569	  background: rgba(92, 255, 176, 0.08);
1570	  border: 1px solid rgba(92, 255, 176, 0.4);
1571	  border-radius: 7px;
1572	  transition: background 0.15s ease, border-color 0.15s ease, transform 0.1s ease;
1573	}
1574	.lc-chip:hover:not(.is-wrong) {
1575	  background: rgba(92, 255, 176, 0.18);
1576	  border-color: rgba(92, 255, 176, 0.7);
1577	  transform: translateY(-1px);
1578	}
1579	.lc-chip kbd {
1580	  display: inline-grid;
1581	  place-items: center;
1582	  min-width: 20px;
1583	  height: 20px;
1584	  font-family: ui-monospace, monospace;
1585	  font-size: 11px;
1586	  font-weight: 700;
1587	  color: #04121a;
1588	  background: linear-gradient(90deg, #5cffb0, #bfffe0);
1589	  border-radius: 4px;
1590	  flex: none;
1591	}
1592	.lc-chip.is-wrong {
1593	  opacity: 0.35;
1594	  cursor: default;
1595	  text-decoration: line-through;
1596	}
1597	
1598	/* The finale: one pre-filled command, one Enter */
1599	.lc-single {
1600	  display: flex;
1601	  align-items: center;
1602	  gap: 8px;
1603	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
1604	  font-size: 16px;
1605	  cursor: pointer;
1606	}
1607	.lc-single .lc-cmd { color: var(--ink); }
1608	.lc-single-cta {
1609	  display: flex;
1610	  align-items: center;
1611	  gap: 10px;
1612	  margin-top: 12px;
1613	  cursor: pointer;
1614	}
1615	.lc-cursor {
1616	  display: inline-block;
1617	  width: 8px;
1618	  height: 16px;
1619	  background: var(--accent);
1620	  animation: term-blink 1s steps(1) infinite;
1621	}
1622	
1623	/* Confirm / dead-end flashes, same voice as the terminal's */
1624	#lc-msg {
1625	  margin-top: 10px;
1626	  min-height: 16px;
1627	  font-size: 12.5px;
1628	  letter-spacing: 0.02em;
1629	  opacity: 0;
1630	  transition: opacity 0.25s ease;
1631	}
1632	#lc-msg.show-ok { opacity: 0.92; color: #7cffb0; }
1633	#lc-msg.show-err { opacity: 0.92; color: #ff8a73; }
1634	
1635	@media (max-width: 680px) {
1636	  #lc-code { top: 124px; left: 16px; padding: 9px 11px; }
1637	  .lc-seg { min-width: 36px; height: 22px; font-size: 10.5px; }
1638	  #lc-console { bottom: 48px; padding: 12px 13px; }
1639	  #lc-question { font-size: 13px; }
1640	  .lc-opt { font-size: 11.5px; }
1641	}
1642	
1643	/* Ignition countdown — 3… 2… 1… IGNITION */
1644	#lc-ignition {
1645	  position: absolute;
1646	  top: 38%;
1647	  left: 50%;
1648	  transform: translate(-50%, -50%);
1649	  font-family: ui-monospace, "SF Mono", Menlo, monospace;
1650	  font-size: 110px;
1651	  font-weight: 700;
1652	  letter-spacing: 0.06em;
1653	  color: #ffe7b0;
1654	  text-shadow: 0 0 34px rgba(255, 210, 122, 0.85), 0 0 90px rgba(255, 210, 122, 0.4);
1655	  pointer-events: none;
1656	}
1657	#lc-ignition.hidden { display: none; }
1658	#lc-ignition.is-go {
1659	  font-size: 64px;
1660	  letter-spacing: 0.22em;
1661	  color: #fff6e6;
1662	}
1663	#lc-ignition.pop { animation: lc-pop 0.9s cubic-bezier(0.16, 1, 0.3, 1) both; }
1664	@keyframes lc-pop {
1665	  0% { opacity: 0; transform: translate(-50%, -50%) scale(1.6); }
1666	  18% { opacity: 1; transform: translate(-50%, -50%) scale(1); }
1667	  80% { opacity: 1; }
1668	  100% { opacity: 0.15; transform: translate(-50%, -50%) scale(0.92); }
1669	}
1670	
1671	/* The ignition flash — one bright gold breath over everything */
1672	#lc-flash {
1673	  position: absolute;
1674	  inset: 0;
1675	  background: radial-gradient(ellipse at 50% 62%,
1676	    rgba(255, 236, 190, 0.95), rgba(255, 210, 122, 0.55) 45%, rgba(255, 180, 90, 0) 75%);
1677	  opacity: 0;
1678	  pointer-events: none;
1679	}
1680	#lc-flash.show { animation: lc-flash 1.4s ease-out both; }
1681	@keyframes lc-flash {
1682	  0% { opacity: 0; }
1683	  12% { opacity: 1; }
1684	  100% { opacity: 0; }
1685	}
1686	
1687	@media (max-width: 680px) {
1688	  #lc-ignition { font-size: 72px; }
1689	  #lc-ignition.is-go { font-size: 38px; }
1690	}
