.ts-group-head {
  font-size: 10px;
  letter-spacing: 0.24em;
  font-weight: 700;
  color: var(--accent-warm);
  margin-bottom: 10px;
}
.ts-ctrl {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 3px 0;
  font-size: 12.5px;
  letter-spacing: 0.04em;
  color: var(--ink);
  opacity: 0.9;
}
.ts-panel .ts-item {
  font-size: 13px;
  letter-spacing: 0.18em;
}
.ts-panel-back {
  display: block;
  margin: 14px auto 0;
}

/* Sound rows: MUSIC ··· ON / VOLUME [slider] 55% */
.ts-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  width: 100%;
  padding: 9px 12px 9px 22px;
  text-align: left;
}
.ts-value {
  color: var(--accent);
  font-weight: 700;
  font-variant-numeric: tabular-nums;
}
.ts-value.is-off { color: var(--accent-warm); }
#ts-volume {
  width: 140px;
  margin-left: auto;
  accent-color: var(--accent-warm);
  cursor: pointer;
}
#ts-volume-pct { min-width: 44px; text-align: right; }

.ts-hint {
  margin-top: 44px;
  font-size: 11px;
  letter-spacing: 0.1em;
  opacity: 0.55;
}

@media (max-width: 680px) {
  .ts-menu { margin-top: 38px; }
  .ts-panel { max-height: 54vh; padding: 16px 18px 12px; }
  .ts-hint { display: none; }
}

