import puppeteer from 'puppeteer-core';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

const browser = await puppeteer.launch({
  executablePath: '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
  headless: 'new',
  args: ['--window-size=1440,900', '--hide-scrollbars', '--autoplay-policy=no-user-gesture-required'],
  defaultViewport: { width: 1440, height: 900, deviceScaleFactor: 2 },
});
const page = await browser.newPage();
page.on('console', (m) => console.log('PAGE:', m.type(), m.text()));
page.on('pageerror', (e) => console.log('PAGEERROR:', e.message));

await page.goto('http://127.0.0.1:5199/', { waitUntil: 'networkidle2', timeout: 60000 });
await sleep(7000); // let the planet bake + loader fade
await page.screenshot({ path: '/tmp/ts-1-title.png' });

// keyboard: down to OPTIONS, enter
await page.keyboard.press('ArrowDown');
await sleep(300);
await page.keyboard.press('Enter');
await sleep(400);
await page.screenshot({ path: '/tmp/ts-2-options.png' });

// CONTROLS
await page.keyboard.press('Enter');
await sleep(400);
await page.screenshot({ path: '/tmp/ts-3-controls.png' });

// back via Esc, down to SOUND, enter
await page.keyboard.press('Escape');
await sleep(300);
await page.keyboard.press('ArrowDown');
await sleep(200);
await page.keyboard.press('Enter');
await sleep(400);
await page.screenshot({ path: '/tmp/ts-4-sound.png' });

// volume row: down, then nudge left twice
await page.keyboard.press('ArrowDown');
await sleep(200);
await page.keyboard.press('ArrowLeft');
await page.keyboard.press('ArrowLeft');
await sleep(300);
await page.screenshot({ path: '/tmp/ts-5-sound-volume.png' });

const vol = await page.evaluate(() => ({
  bgm: document.getElementById('bgm').volume.toFixed(2),
  panel: document.getElementById('audio-volume').value,
  paused: document.getElementById('bgm').paused,
}));
console.log('VOLUME SYNC:', JSON.stringify(vol));

// toggle music off via the MUSIC row
await page.keyboard.press('ArrowUp');
await sleep(200);
await page.keyboard.press('Enter');
await sleep(400);
const offState = await page.evaluate(() => ({
  paused: document.getElementById('bgm').paused,
  label: document.getElementById('ts-music-state').textContent,
}));
console.log('MUSIC TOGGLED:', JSON.stringify(offState));
await page.screenshot({ path: '/tmp/ts-6-music-off.png' });

// back out to main, START GAME
await page.keyboard.press('Escape');
await sleep(200);
await page.keyboard.press('Escape');
await sleep(200);
await page.keyboard.press('Enter');
await sleep(1200);
await page.screenshot({ path: '/tmp/ts-7-started.png' });

const after = await page.evaluate(() => ({
  titleHidden: document.getElementById('title-screen').classList.contains('hidden'),
  bodyClass: document.body.className,
  hintVisible: !document.getElementById('hint').classList.contains('hidden'),
}));
console.log('AFTER START:', JSON.stringify(after));

await browser.close();
console.log('done');

